select *
from (

) t
where 1 = 1

  and (
    t.biz_no like concat('%', #{keyword}, '%')
    or t.order_no like concat('%', #{keyword}, '%')
    or t.instrument_name like concat('%', #{keyword}, '%')
    or t.department_name like concat('%', #{keyword}, '%')
    or t.user_name like concat('%', #{keyword}, '%')
    or t.remark like concat('%', #{keyword}, '%')
  )


  and t.biz_type = #{bizType}


  and t.inout_type = #{inoutType}


  and t.instrument_id = #{instrumentId}


  and t.department_id = #{departmentId}


  and t.occur_time >= #{startTime}


  and t.occur_time <= #{endTime}


  and t.department_id = #{scopeDepartmentId}

order by t.occur_time desc, t.biz_type desc
limit #{offset}, #{pageSize}

